const toolCall = $json.choices[0].message.tool_calls[0];
const args = JSON.parse(toolCall.function.arguments || '{}');
const weather = {
  islamabad: { temperature: '28 deg C', condition: 'Partly Cloudy', humidity: '55%' },
  karachi: { temperature: '34 deg C', condition: 'Hot and Sunny', humidity: '70%' },
  lahore: { temperature: '32 deg C', condition: 'Hazy', humidity: '60%' }
};
const city = (args.city || 'Islamabad').toLowerCase();
return [{ json: { tool_call_id: toolCall.id, tool_name: 'get_weather', arguments: args, result: { city: args.city || 'Islamabad', ...(weather[city] || weather.islamabad) } } }];

const toolCall = $json.choices[0].message.tool_calls[0];
const args = JSON.parse(toolCall.function.arguments || '{}');
const rates = { PKR: 1, USD: 278.5, GBP: 352, AED: 75.8 };
const from = String(args.from_currency || 'PKR').toUpperCase();
const to = String(args.to_currency || 'PKR').toUpperCase();
const pkr = Number(args.amount || 0) * rates[from];
const converted = pkr / rates[to];
return [{ json: { tool_call_id: toolCall.id, tool_name: 'convert_currency', arguments: args, result: { original: `${args.amount} ${from}`, converted: `${converted.toFixed(2)} ${to}` } } }];

const toolCall = $json.choices[0].message.tool_calls[0];
const args = JSON.parse(toolCall.function.arguments || '{}');
const city = String(args.city || 'Lahore').toLowerCase();
const base = city === 'islamabad' ? 32000 : city === 'karachi' ? 26000 : 24000;
return [{ json: { tool_call_id: toolCall.id, tool_name: 'get_room_cost', arguments: args, result: { city: args.city || 'Lahore', university: args.university || 'University area', monthly_room_cost: `PKR ${base.toLocaleString()}`, note: 'Shared hostel room estimate near campus.' } } }];

const toolCall = $json.choices[0].message.tool_calls[0];
const args = JSON.parse(toolCall.function.arguments || '{}');
const routes = { 'lahore-karachi': 7500, 'islamabad-lahore': 3200, 'islamabad-karachi': 9000 };
const key = `${String(args.from_city || '').toLowerCase()}-${String(args.to_city || '').toLowerCase()}`;
const reverse = `${String(args.to_city || '').toLowerCase()}-${String(args.from_city || '').toLowerCase()}`;
const cost = routes[key] || routes[reverse] || 5000;
return [{ json: { tool_call_id: toolCall.id, tool_name: 'get_transport_cost', arguments: args, result: { route: `${args.from_city} to ${args.to_city}`, estimated_cost: `PKR ${cost.toLocaleString()}`, mode: 'Bus or economy train estimate' } } }];

const current = $items('Turn Counter').at(-1).json;
const toolMessage = { role: 'tool', tool_call_id: $json.tool_call_id, content: JSON.stringify($json.result) };
const assistantMessage = $items('Travel Assistant LLM').at(-1).json.choices[0].message;
return [{ json: { ...current, messages: [...current.messages, assistantMessage, toolMessage], tool_calls: [...(current.tool_calls || []), { tool_name: $json.tool_name, arguments: $json.arguments, result: $json.result }] } }];
